(function($){$(document).ready(function(){if(window.elementor){elementor.hooks.addFilter('element/view',function(groups_prototype,element){if(element.get('elType')==='column'){return groups_prototype.extend({getContextMenuGroups:function(){return groups_prototype.prototype.getContextMenuGroups.apply(this,arguments);}})}
return groups_prototype;});elementor.hooks.addFilter('elements/column/contextMenuGroups',addItemToContextMenu)}});function addItemToContextMenu(groups,element){var clipboard_index=groups.findIndex(function(item){return'addNew'===item.name;});groups[clipboard_index].actions.push({name:'exad-add-child-section',title:'Add Child Section',icon:'context-menu-icon exad exad-logo',callback:function(){insertNestedSection(element);},isEnabled:function(){return true;}});return groups}
function insertNestedSection(element){var element_view=element.getContainer().view;if(element_view.getElementType()==='column'){element_view.addElement({elType:'section',isInner:true,settings:{},elements:[{id:elementorCommon.helpers.getUniqueId(),elType:'column',isInner:true,settings:{_column_size:100},elements:[]}]});}}})(jQuery);